  ('judicial-de09bf8b-moex-00309', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-110-9b7ab1bb', 'sub-judicial-de09bf8b-10', NULL, 'essay', '乙經營老字號餐廳，受新冠疫情衝擊，餐廳生意受到嚴重影響，於是與
甲成立新臺幣（下同）200萬元消費借貸契約，並提供自己所有A餐廳
之不動產所有權為甲之債權設定第二順位抵押權，且委任其好友丙，提
供連帶保證。乙曾以 A 餐廳不動產所有權設定抵押權，向某銀行貸款
1000萬元，尚有500 萬元之貸款尚未繳清。乙最終仍因不抵疫情而需結
束餐廳營業。除了上述債務之外，乙尚積欠員工6 個月薪資，共 660 萬
元。A餐廳拍賣價格為 950萬元。請問乙之債權人應如何主張其債權以
及甲是否得直接向保證人丙請求債款之清償？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "1d4a457a2d8f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "107", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00310', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-110-5b9f6b8d', 'sub-judicial-de09bf8b-12', NULL, 'essay', '甲為某國立大學法律系三年級學生。甲在修習該系必修之行政法科目
時，其繳交之書面報告成績僅獲五十五分。依據該科授課教師之評量規
則，平時成績係依據學生繳交之書面報告成績計算，占學期總成績百分
之三十，而期末考筆試成績則占學期總成績百分之七十。甲覺得老師乙
對其書面報告成績之評分不公，經向學校提起申訴未獲救濟後，乃向教
育部提起訴願。請問其提起之訴願在程序上是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "96d4829e5b11", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "107", "s": "0304", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法與法院組織法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00311', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-110-5b9f6b8d', 'sub-judicial-de09bf8b-12', NULL, 'essay', 'A市政府環保局認定甲晶圓代工事業排放之廢水中含有有害健康物質，
有危害公眾健康之虞，乃勒令甲事業停工。甲事業認為 A市政府環保局
未將其排放之廢水送請專業鑑定，根本是未審先判，遂向 A市政府提起
訴願。惟甲事業認為停工將對其營業造成嚴重之損害，情況緊急，故逕
向行政法院聲請停止執行。請問行政法院應如何處理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "96d4829e5b11", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "107", "s": "0304", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法與法院組織法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00312', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-110-5b9f6b8d', 'sub-judicial-de09bf8b-12', NULL, 'essay', '最高法院民事庭各庭審理案件時，如經評議後認採為裁判基礎之法律見
解，與先前裁判之法律見解歧異者，依法院組織法規定應以裁定敘明理
由提案予民事大法庭裁判，請說明下列問題：
該民事庭裁定前，應經何程序始得裁定？（10分）
民事大法庭審判長與庭員如何產生？（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "96d4829e5b11", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "107", "s": "0304", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法與法院組織法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00313', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-110-5b9f6b8d', 'sub-judicial-de09bf8b-12', NULL, 'essay', '某地方檢察署檢察官為偵查被告甲所涉及殺人案件時，向法院聲請核發
搜索票，法院受理後，分案由該法院強制處分專庭法官乙承辦。其後該
案經檢察官偵查終結並起訴甲，案件繫屬法院分案時，請附理由說明乙
法官依法院組織法規定是否應迴避？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:20+00:00", "source_pdf_sha1": "96d4829e5b11", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "107", "s": "0304", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法與法院組織法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00001', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', '某甲與仇家乙、丙狹路相逢，被乙、丙二人聯手毆傷，甲得於何時提出
告訴？若乙表現悔意，願意賠償，但丙拒不賠償，甲得否僅對丙提出告
訴，不對乙提出告訴？又若甲於提出告訴後，於檢察官偵查時撤回告訴，
得否再行告訴？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "98d5c3509877", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0514", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00002', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', '甲、乙二人因糾紛而發生肢體衝突，甲憤而提告，案經第一審法院審理，
於辯論終結後定期宣判。時至宣判期日，甲、乙親自到場聽判，法官宣
示判決：乙成立傷害罪，有期徒刑一年六月，緩刑三年。乙聞之，在宣
判庭上，大聲吼叫司法不公，表示自己要放棄上訴，藉此表達對於司法
不公的沉痛抗議。然而，十日之後，乙冷靜下來，覺得自己應該還是要
上訴救濟。試問：乙可否提出上訴？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "98d5c3509877", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0514", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00003', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', '某晚，甲趁月黑風高，獨自潛入臺北某富豪宅邸的東廂房行竊，結果失
風被捕；恰巧甲在該豪宅行竊的同時，乙也趁著夜色在同一豪宅的西廂
房行竊，並於不久後被緝捕到案。甲、乙的竊案，經檢警偵辦後，檢察
官均提起公訴。甲竊案經第一審臺北地方法院宣判，甲認為處罰太重，
乃上訴至臺灣高等法院；此時，乙竊案尚在第一審臺北地方法院審理中。
試問：臺灣高等法院得否以裁定命臺北地方法院將乙竊案移送臺灣高等
法院合併審判？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "98d5c3509877", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0514", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00004', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', '司法警察在調查某詐欺案，發現甲似乎涉有嫌疑，疑為詐欺集團成員，
警官指示警員先行前往甲住處附近觀察。警員在甲住處附近觀察時，發
現有人出入甲住處，乃上前詢問，方才獲知該人為甲的室友乙。乙是大
學生，其與甲是國中同學，兩人合租兩廳兩室一衛的公寓住房，二人共
用客廳、餐廳與衛浴間，各自有一間起居臥室。警員出示證件後，禮貌
詢問乙能否入內搜索，乙表示同意。試問：警員可否基於乙的同意，進
入甲、乙的租屋處搜索？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "98d5c3509877", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0514", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00005', 'judicial-f0899a01', 'judicial-f0899a01-moex-114-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '下列何項原則不屬於罪刑法定原則之內涵？', '["禁止類推適用原則", "罪刑明確性原則", "不利益變更禁止原則", "禁止溯及既往原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:44+00:00", "source_pdf_sha1": "db7b19bdcc55", "answer_pdf_sha1": "322a1e496452", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
